import React, { useState, useEffect, useCallback } from 'react';
import { useForm } from 'react-hookform';
import { useUser } from '../../hooks/useUser';

interface PostEditorProps {
  initialPost?: {
    title?: string;
    content?: string;
  };
}

const PostEditor: React.FC<PostEditorProps> = ({ initialPost = {} }) => {
  const { user } = useUser();
  const [isSaving, setIsSaving] = useState(false);
  const { data, handleSubmit, register, formState: { errors } } = useForm({
    defaultValues: initialPost,
  });

  const isValid = !!data?.title && !!data?.content;

  const onSubmit = async (data: any) => {
    setIsSaving(true);
    try {
      // Simulate an API call
      await new Promise(resolve => setTimeout(resolve, 1000));
      // Simulate success
      console.log('Post saved successfully:', data);
    } catch (error) {
      console.error('Error saving post:', error);
      // Handle error - could display an error message to the user
    } finally {
      setIsSaving(false);
    }
  };

  const toggleSaveDraft = useCallback(() => {
    // Disable if invalid or saving
    if (!isValid || isSaving) {
      return;
    }

    // Simulate saving draft (replace with actual logic)
    console.log('Saving draft...');
  }, [isValid, isSaving]);

  return (
    <form onSubmit={handleSubmit(onSubmit)}>
      <div>
        <label htmlFor="title">Title:</label>
        <input
          type="text"
          id="title"
          {...register('title')}
          onBlur={() => {
            if (!data?.title) {
              errors.title = { message: 'Title is required' };
            } else {
              errors.title = undefined;
            }
          }}
        />
        {errors.title && <div>{errors.title.message}</div>}
      </div>
      <div>
        <label htmlFor="content">Content:</label>
        <textarea
          id="content"
          {...register('content')}
          onBlur={() => {
            if (!data?.content) {
              errors.content = { message: 'Content is required' };
            } else {
              errors.content = undefined;
            }
          }}
        />
        {errors.content && <div>{errors.content.message}</div>}
      </div>
      <button type="submit" disabled={isSaving}>
        Save
      </button>
      <button type="button" disabled={!isValid || isSaving} onClick={toggleSaveDraft}>
        Save Draft
      </button>
    </form>
  );
};

describe('PostEditor', () => {
  it('should disable the Save Draft button when the form is invalid', () => {
    const wrapper = shallow(<PostEditor />);
    expect(wrapper.find('button').find('button').prop('disabled')).toBe(true);
  });

  it('should disable the Save Draft button when a save request is in-flight', () => {
    const wrapper = shallow(<PostEditor />);
    wrapper.find('button').find('button').simulate('click');
    wrapper.update();
    expect(wrapper.find('button').prop('disabled')).toBe(true);
  });

  it('should enable the Save Draft button when the form is valid and no save request is in-flight', () => {
    const wrapper = shallow(<PostEditor />);
    wrapper.find('input[type="text"]').instance().fill('Test Title');
    wrapper.find('textarea').instance().fill('Test Content');
    wrapper.find('button').find('button').simulate('click');
    wrapper.update();
    expect(wrapper.find('button').prop('disabled')).toBe(false);
  });
});
