import React, { useState, useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { useMutation } from '@apollo/client';
import { POST_EDITOR_SAVE_MUTATION } from '../graphql/mutations';

const PostEditor = () => {
  const [isFormInvalid, setIsFormInvalid] = useState(false);
  const [isSaveInFlight, setIsSaveInFlight] = useState(false);
  const [isButtonEnabled, setIsButtonEnabled] = useState(false);

  const { register, handleSubmit, errors } = useForm();
  const [save, { loading, error }] = useMutation(POST_EDITOR_SAVE_MUTATION);

  useEffect(() => {
    const validateForm = () => {
      const isValid = Object.values(errors).every((error) => error.message === '');
      setIsFormInvalid(!isValid);
    };
    validateForm();
  }, [errors]);

  useEffect(() => {
    const handleSaveInFlight = () => {
      setIsSaveInFlight(loading);
    };
    handleSaveInFlight();
  }, [loading]);

  const onSubmit = async (data) => {
    if (isFormInvalid || isSaveInFlight) return;
    try {
      await save({ variables: data });
      setIsSaveInFlight(false);
      setIsButtonEnabled(true);
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <form onSubmit={handleSubmit(onSubmit)}>
      {/* form fields */}
      <button type="submit" disabled={isFormInvalid || isSaveInFlight}>
        {isButtonEnabled ? 'Save' : 'Save Draft'}
      </button>
    </form>
  );
};

export default PostEditor;
```

