Here's a sample implementation in TypeScript that includes a warning banner when the user tries to navigate away with unsaved changes. This example assumes you're using React for rendering the UI.

```typescript
import React, { useState, useEffect } from 'react';

interface EditorProps {
  onEditorChange: (changes: any) => void;
  onEditorCancel: () => void;
}

const Editor: React.FC<EditorProps> = ({ onEditorChange, onEditorCancel }) => {
  const [editorContent, setEditorContent] = useState<string>('');
  const [hasUnsavedChanges, setHasUnsavedChanges] = useState(false);

  useEffect(() => {
    const handleEditorChange = () => {
      setHasUnsavedChanges(false);
    };

    const handleEditorCancel = () => {
      setHasUnsavedChanges(true);
    };

    onEditorChange(() => {
      handleEditorChange();
    });

    onEditorCancel(() => {
      handleEditorCancel();
    });

    return () => {
      // Clean up
    };
  }, [onEditorChange, onEditorCancel]);

  const handleEditorSave = () => {
    // Save editor content
    console.log('Editor content saved:', editorContent);
    setHasUnsavedChanges(false);
  };

  return (
    <div>
      {hasUnsavedChanges && (
        <div className="warning-banner">
          <p>
            You have unsaved changes. Are you sure you want to leave the editor?
          </p>
          <button onClick={handleEditorSave}>Save and Continue</button>
          <button onClick={onEditorCancel}>Cancel</button>
        </div>
      )}
      <textarea
        value={editorContent}
        onChange={(e) => setEditorContent(e.target.value)}
        rows={10}
        cols={50}
      />
    </div>
  );
};

export default Editor;
```

In this example, we use the `useState` hook to keep track of whether the user has unsaved changes. We also use the `useEffect` hook to listen for changes to the editor content and the cancel button. When the user tries to leave the editor with unsaved changes, we display a warning banner with two buttons: "Save and Continue" and "Cancel". The "Save and Continue" button saves the editor content and sets `hasUnsavedChanges` to `false`, while the "Cancel" button sets `hasUnsavedChanges` to `true` and calls the `onEditorCancel` callback.

You can customize the warning banner and the buttons to fit your specific use case.

