    setHasUnsavedChanges(false);
  };

  const handleEditorCancel = () => {
    setHasUnsavedChanges(true);
  };

  return (
    <div>
      <h1>Editor</h1>
      {hasUnsavedChanges && (
        <div className="warning-banner">
          <p>
            You have unsaved changes. Are you sure you want to leave the editor?
          </p>
          <button onClick={handleEditorSave}>Save and Continue</button>
          <button onClick={handleEditorCancel}>Cancel</button>
        </div>
      )}
      <Editor
        onEditorChange={handleEditorChange}
        onEditorCancel={handleEditorCancel}
      />
    </div>
  );
};

export default App;
```

In this example, we define two state variables: `editorContent` and `hasUnsavedChanges`. We also define two callback functions: `handleEditorChange` and `handleEditorCancel`. When the user makes changes to the editor, we update the `editorContent` state variable and set `hasUnsavedChanges` to `false`. When the user tries to leave the editor, we set `hasUnsavedChanges` to `true` and display the warning banner.

