import React, { useState } from 'react';
import { useForm } from 'react-hook-form';
import { useMutation } from '@apollo/client';
import { POST_EDITOR_SAVE_MUTATION } from '../graphql/mutations';

const PostEditor = () => {
  const [isSaving, setIsSaving] = useState(false);
  const [isValid, setIsValid] = useState(true);
  const { register, handleSubmit, errors } = useForm();

  const [save, { loading, error }] = useMutation(POST_EDITOR_SAVE_MUTATION);

  const onSubmit = async (data) => {
    setIsSaving(true);
    try {
      await save({ variables: data });
      setIsSaving(false);
    } catch (error) {
      setIsSaving(false);
    }
  };

  const handleInputChange = (event) => {
    setIsValid(validateForm(event.target));
  };

  const validateForm = (event) => {
    const errors = {};
    if (!event.target.value) {
      errors.title = 'Title is required';
    }
    return Object.keys(errors).length === 0;
  };

  return (
    <form onSubmit={handleSubmit(onSubmit)}>
      <label>
        Title:
        <input type="text" {...register('title')} onChange={handleInputChange} />
        {errors.title && <div style={{ color: 'red' }}>{errors.title}</div>}
      </label>
      <button type="submit" disabled={isSaving || !isValid}>
        {isSaving ? 'Saving...' : 'Save Draft'}
      </button>
    </form>
  );
};

export default PostEditor;
```

