```

2. In your component's TypeScript file:
```typescript
@Component({
  // ... other component metadata
})
export class YourComponent implements OnInit {
  isAdmin: boolean = false;

  constructor(private authService: AuthService) {}

  ngOnInit() {
    this.checkAdminStatus();
  }

  checkAdminStatus() {
    // Method 1: Using an authentication service
    this.isAdmin = this.authService.getCurrentUserRole() === 'admin';

    // Method 2: If using user object
    const currentUser = this.authService.getCurrentUser();
    this.isAdmin = currentUser && currentUser.role === 'admin';

    // Method 3: If using a simple boolean check
    this.isAdmin = this.authService.isAdmin();
  }

  deleteItem() {
    // Only proceed if user is admin (additional backend check recommended)
    if (this.isAdmin) {
      // Delete logic here
    }
  }
}
```

3. Example of an Authentication Service:
```typescript
@Injectable({
  providedIn: 'root'
})
export class AuthService {
  private currentUser: any;

  constructor() {
    // Load user from localStorage or authentication state
    this.currentUser = this.loadUserFromStorage();
  }

  getCurrentUserRole() {
    return this.currentUser ? this.currentUser.role : null;
  }

  isAdmin() {
    return this.getCurrentUserRole() === 'admin';
  }

  getCurrentUser() {
    return this.currentUser;
  }

  private loadUserFromStorage() {
    const userJson = localStorage.getItem('currentUser');
    return userJson ? JSON.parse(userJson) : null;
  }
}
```

4. Additional Security Considerations:
- Always implement server-side authorization checks
- Don't rely solely on client-side hiding of buttons
- Validate user permissions on the backend before performing delete operations

5. Alternative Approach using Structural Directive:
```html
<!-- More explicit admin check -->
<ng-container *ngIf="authService.isAdmin()">
  <button (click)="deleteItem()" class="delete-btn">
    Delete
  </button>
</ng-container>
```

6. Role-Based Access Control (RBAC) Example:
```typescript
@Component({
  template: `
    <button 
      *ngIf="hasPermission('delete')" 
      (click)="deleteItem()">
      Delete
    </button>
  `
})
export class YourComponent {
  constructor(private permissionService: PermissionService) {}

  hasPermission(action: string): boolean {
    return this.permissionService.checkPermission(action);
  }
}

@Injectable({
  providedIn: 'root'
})
export class PermissionService {
  checkPermission(action: string): boolean {
    const userRoles = this.getCurrentUserRoles();
    const requiredRoles = this.getRequiredRolesForAction(action);

    return userRoles.some(role => requiredRoles.includes(role));
  }

  private getCurrentUserRoles() {
    // Retrieve current user's roles
    return ['admin', 'manager'];
  }

  private getRequiredRolesForAction(action: string) {
    const roleMap = {
      'delete': ['admin'],
      'edit': ['admin', 'manager']
    };
    return roleMap[action] || [];
  }
}
```

Best Practices:
- Always implement server-side authorization
- Use a centralized authentication/authorization service
- Keep authorization logic separate from components
- Use role-based access control for more granular permissions

