  // Get current user from auth context
  const { user } = useAuth();

  // Function to check if user has approver permission
  const hasApproverPermission = () => {
    // Example permission check
    return user?.roles?.includes('approver') || 
           user?.permissions?.includes('order_approve');
  };

  // Function to handle order approval
  const handleApprove = async () => {
    try {
      // Call API to approve the order
      await approveOrder(order.id);

      // Optionally update local state or trigger refresh
      // onOrderApproved(order.id);
    } catch (error) {
      // Handle approval error
      console.error('Failed to approve order', error);
    }
  };

  // Conditional rendering of approve button
  const canApproveOrder = 
    order.status === 'pending' && hasApproverPermission();

  return (
    <div className="order-details">
      <h2>Order Details</h2>

      {/* Order information */}
      <div>
        <p>Order ID: {order.id}</p>
        <p>Status: {order.status}</p>
        {/* Other order details */}
      </div>

      {/* Conditionally render approve button */}
      {canApproveOrder && (
        <Button 
          variant="primary" 
          onClick={handleApprove}
        >
          Approve Order
        </Button>
      )}
    </div>
  );
};

// Example of an approval function (would typically be in a service file)
const approveOrder = async (orderId) => {
  try {
    const response = await fetch(`/api/orders/${orderId}/approve`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        // Include authentication token
        'Authorization': `Bearer ${localStorage.getItem('token')}`
      }
    });

    if (!response.ok) {
      throw new Error('Failed to approve order');
    }

    return await response.json();
  } catch (error) {
    console.error('Approval error:', error);
    throw error;
  }
};

export default OrderDetails;
```

