import { useAuth } from './AuthContext';

export const useOrderPermissions = (order) => {
  const { user } = useAuth();

  const canApproveOrder = React.useMemo(() => {
    const hasApproverRole = user?.roles?.includes('approver');
    const hasApprovePermission = user?.permissions?.includes('order_approve');

    return order.status === 'pending' && 
           (hasApproverRole || hasApprovePermission);
  }, [user, order.status]);

  return {
    canApproveOrder
  };
};

// In your component
const OrderDetails = ({ order }) => {
  const { canApproveOrder } = useOrderPermissions(order);

  return (
    <div>
      {canApproveOrder && (
        <Button onClick={handleApprove}>
          Approve Order
        </Button>
      )}
    </div>
  );
};
